import type { Equipment, QuoteRequest, Service } from './types';
import imageData from './placeholder-images.json';

const getImage = (id: string) => {
  const image = imageData.placeholderImages.find(img => img.id === id);
  return image || { imageUrl: 'https://picsum.photos/seed/placeholder/600/400', imageHint: 'placeholder image' };
}

